#!/bin/bash

# Create directories and set permissions to 777
mkdir -p /var/www/{public,private}
chmod -R 777 /var/www/{public,private}

# Install Composer
curl -sS https://getcomposer.org/installer | php -- --install-dir=/usr/local/bin --filename=composer

# Install Laravel
cd /var/www && composer create-project laravel/laravel public 5.4.*

# Create .env file and set permissions to 600
cp .env.example .env
chmod -R 777 .env

# Install dependencies with Composer
cd /var/www/public && composer install --no-dev

